import pytest

def test_mobile_cheque_deposit_invalid_micr_returns_422(
    auth_session,           # <fixture> returns authenticated requests.Session
    invalid_micr_image,     # <fixture> returns bytes of a corrupt MICR cheque image
    api_base_url,           # <fixture> returns base URL string
):
    payload = {
        "amount": "1000.00",
        "currency": "USD",
    }
    files = {"image": ("bad_cheque.jpg", invalid_micr_image, "image/jpeg")}

    resp = auth_session.post(
        f"{api_base_url}/deposits/mobile-cheque",
        data=payload,
        files=files,
    )

    assert resp.status_code == 422, f"Expected 422, got {resp.status_code}: {resp.text}"
    body = resp.json()
    assert body.get("error_code") == "MICR_DECODE_FAILURE"
    assert "deposit_id" not in body

import pytest

@pytest.mark.parametrize("image_fixture,amount,exp_status,exp_decisioning,exp_error", [
    ("valid_cheque_image",   "4999.99", 202, False, None),
    ("valid_cheque_image",   "5000.01", 202, True,  None),
    ("invalid_micr_image",   "4999.99", 422, None,  "MICR_DECODE_FAILURE"),
    ("invalid_micr_image",   "5000.01", 422, None,  "MICR_DECODE_FAILURE"),
])
def test_mobile_cheque_deposit_decision_table_amount_and_image_quality_matrix(
    request,
    auth_session,   # <fixture> returns authenticated requests.Session
    api_base_url,   # <fixture> returns base URL string
    image_fixture, amount, exp_status, exp_decisioning, exp_error,
):
    image_bytes = request.getfixturevalue(image_fixture)
    payload = {"amount": amount, "currency": "USD"}
    files = {"image": ("cheque.jpg", image_bytes, "image/jpeg")}

    resp = auth_session.post(
        f"{api_base_url}/deposits/mobile-cheque",
        data=payload, files=files,
    )
    body = resp.json()

    assert resp.status_code == exp_status, f"[{image_fixture},{amount}] {resp.text}"
    if exp_error:
        assert body.get("error_code") == exp_error
    else:
        assert body["status"] == "deposit_pending"
        assert body["decisioning_required"] is exp_decisioning
        assert body.get("deposit_id")
